!function(){try{var e="undefined"!=typeof window?window:"undefined"!=typeof global?global:"undefined"!=typeof globalThis?globalThis:"undefined"!=typeof self?self:{},n=(new e.Error).stack;n&&(e._sentryDebugIds=e._sentryDebugIds||{},e._sentryDebugIds[n]="5aeedaa9-3b16-47c3-ae3c-3344ff91b0f0",e._sentryDebugIdIdentifier="sentry-dbid-5aeedaa9-3b16-47c3-ae3c-3344ff91b0f0")}catch(e){}}();var _global="undefined"!=typeof window?window:"undefined"!=typeof global?global:"undefined"!=typeof globalThis?globalThis:"undefined"!=typeof self?self:{};_global.SENTRY_RELEASE={id:"endfield-returning-user-reward-web@1.0.0"},(self.webpackChunkendfield_returning_user_reward_web=self.webpackChunkendfield_returning_user_reward_web||[]).push([[719],{59719:function(e,n,i){i.r(n),i.d(n,{locale:function(){return a}});var r=i(23068),t=JSON.parse('{"title":"Protokoll-Neuverbindung","description":"Willkommen zurück auf Talos-II, Endministrator.","guide":{"character":"Perlica","lines":"Endmin, wie war der Urlaub? An Bord der Dijiang ist jede Menge passiert, und ich soll dich von den Operatoren aus unserer Behandlungsabteilung daran erinnern, dich für deine physische Untersuchung anzumelden! Es vermissen dich alle, und ich … ich warte auch auf dich, Endmin.","button":"Protokoll-Neuverbindung"},"home":{"title":"Protokoll-Neuverbindung","timeCount":"{{DD}} T {{HH}} Std.","tabs":{"checkIn":"Neuverbindung-Anmeldung","task":"Neuverbindung-Aufgaben","survey":"Rückkehrerumfrage"},"checkIn":{"title":"Neuverbindung-Anmeldung","intro":"Nimm 7 Tage lang am Event [Neuverbindung-Anmeldung] teil und hole [Oro-Beryll] ×2.000 und andere Belohnungen ab!"},"task":{"intro":"Nimm am Event [Neuverbindung-Aufgaben] teil und schließe verschiedene Aufgaben ab, um <b>[RK-Genehmigung: Einfach] ×4</b> und andere Belohnungen zu erhalten!","taskStatus":{"claimable":"Abholen","ongoing":"Unvollständig","claimed":"Abgeholt"},"claimAvailable":"Alle abholen","currentPoint":"Aktuelle Punkte","taskContent":{"daily_login":"Logge dich 1-mal täglich im Spiel ein (kann 7-mal abgeschlossen werden).","deploy_factory":"Platziere eine beliebige AIK-Fabrikanlage.","battle_enemy":"Besiege 10 beliebige Gegner.","clear_stage":"Schließe eine beliebige Protokoll-Dimension ab.","manufacture":"Hol auf der Dijiang 1-mal Produkte aus einer beliebigen Produktionskabine ab.","upgrade_role_level":"Erhöhe 1-mal das Level eines beliebigen Operators.","collect_ore":"Sammle 1-mal ein beliebiges Mineralienerz.","trade_goods":"Treibe 1-mal mit einem beliebigen Außenposten Handel.","buy_goods":"Kaufe 1-mal Waren von einem beliebigen Vorratneuverteilungs-System.","trade_credit":"Kaufe 1-mal Gegenstände im Credit-Laden.","collect_item":"Sammle 8 Rosafarbene Röhrenpilze.","ap_cost":"Verbrauche 1.000 Verstandspunkte.","boss_challenge":"Schließe eine beliebige RE-Krise-Herausforderung 1-mal ab.","world_battle":"Säubere 1-mal Energie-Alluvium (Temporäres Energie-Alluvium zählt ebenfalls)."}},"minimumTimeCount":"< 1 STD.","survey":{"surveyStatus":{"not_started":"Noch nicht begonnen","claimed":"Abgeschlossen"},"goToButton":"Los","unlockText":"Wird in {{timeCount}} freigeschaltet","rewardTip":"Zum Erhalt bitte Umfrage abschließen","surveyContent":{"survey_1":"Starttag-Rückkehrerumfrage","survey_2":"Rückkehrer-Erlebnisumfrage"},"callbackModal":{"title":"SYSTEMBENACHRICHTIGUNG","content":"Bitte geh auf die neue Seite, um an der Umfrage teilzunehmen.","button":"Abgeschlossen"}}},"rule":{"title":"[Protokoll-Neuverbindung] Eventdetails","content":"<b>– Teilnahmevoraussetzungen –</b>\\n<span>· Endministrator-Autoritätslevel ≥ 3</span>\\n<span>· Abschluss der Hauptmission [Kapitel I, Prozess I: Talfahrt].</span>\\n<span>· Kein Login ins Spiel für ≥ 21 Tage in Folge</span>\\n<span>· Teilnahme am letzten Event [Protokoll-Neuverbindung] vor ≥ 42 Tagen</span>\\n<span>· Rückkehr-Status des Endministrators ist für die Dauer des Events [Protokoll-Neuverbindung] aktiv.</span>\\n\\n<b>– Eventregeln –</b>\\n<span>· Für den ersten Besuch der Eventseite des Events [Protokoll-Neuverbindung] erhältst du eine Protokoll-Neuverbindungs-Belohnung, Endministrator.</span>\\n<span>· Besuche während des Events die Seite [Protokoll-Neuverbindung] und verdiene Belohnungen für die Teilnahme an [Neuverbindung-Anmeldungs] und [Neuverbindung-Aufgaben].</span>\\n<span>· Melde dich während des Events jeden Tag bei [Neuverbindung-Anmeldung] an und erhalte Belohnungen. Du kannst 7-mal eine tägliche Anmeldung vornehmen.</span>\\n<span>· Schließe während des Events [Neuverbindung-Aufgaben] ab und verdiene Eventpunkte und Belohnungen. Für das Sammeln einer bestimmten Anzahl an Punkten erhältst du zusätzliche Belohnungen.</span>\\n<span>Die Datenverarbeitung für [Neuverbindung-Aufgaben] kann leicht verzögert erfolgen. Warte nach dem Abschluss von Aufgabenbedingungen 2–5 Minuten, bis die Daten synchronisiert wurden.</span>\\n<span>· Alle Eventbelohnungen erhältst du über das spielinterne Nachrichtensystem. Nachrichten mit Belohnungen laufen nach 30 Tagen ab, also vergiss nicht, sie rechtzeitig abzuholen, Endministrator.</span>\\n<span>· Das Event endet 14 Tage nach deiner Teilnahme und schließt um 4:00 Uhr (Serverzeit).</span>"},"rewardModal":{"title":"Belohnungen erhalten","prompt":"Diese Belohnungen wurden dir als Mail gesendet. Vergiss nicht, sie abzuholen, Endmin.","pointTitle":"Punkte erhalten","closeTip":"Zum Schließen klicken","closeTip_PC":"Zum Schließen klicken","closeTip_MB":"Zum Schließen antippen"},"gameItem":{"item_gold":{"name":"T-Kreditscheine","usage":"Wird mit „TK“ abgekürzt. Diese Währung wird vielerorts anerkannt und verwendet.","desc":"Eine beliebte, mit fortschrittlichsten Techniken gegen Fälschungen abgesicherte Währung. Eine Währung, mit der man tatsächlich etwas kaufen kann, ist eine gute Währung."},"item_diamond":{"name":"Oro-Beryll","usage":"Ein künstliches Material, das oft bei der Rekrutierung neuer Operatoren zum Einsatz kommt.","desc":"Ein besonderes Produkt geschnittener Origeometrie. Aufgrund ihrer Schönheit und der vielfältigen Einsatzmöglichkeiten sind diese Steine äußerst beliebt."},"item_expcard_stage1_high":{"name":"Fortgeschrittene Kampfaufzeichnung","usage":"Ein Material zum Aufleveln von Operatoren auf Lvl. 1–60, das sehr viele EP verleiht.","desc":"Ein Datenträger mit Videoaufzeichnungen von Kämpfen. Neue Operatoren können sich damit neue Kenntnisse aneignen. Er enthält außerdem Simulationen historischer Gefechte, die einem vermitteln, wie brutal die Kriege waren, die auf Talos-II ausgetragen wurden."},"item_weapon_expcard_high":{"name":"Waffen-INSP-Set","usage":"Ein Material, das sehr viele Waffen-EP verleiht.","desc":"Ein Einweg-Werkzeugset mit AIK-Technologie. Ermöglicht die automatische gründliche Analyse der gesamten Waffenstruktur. Repariert außerdem interne Materialschäden und verbessert die Leistung der Waffe deutlich."},"item_char_break_stage_1_2":{"name":"Protodisk","usage":"Ein Material, das Operatoren auf E1 oder E2 befördern kann.","desc":"Eine besondere Disk, die mit Techno-Protokoll und herkömmlichen Datengravurprozessen gefertigt wurde. Wird oft von Operatoren beim Training eingesetzt und mit anderen Geräten kombiniert, um körperlicher Erschöpfung entgegenzuwirken."},"item_ticketgacha_standard_single":{"name":"RK-Genehmigung: Einfach","usage":"Ein internes Zertifikat von Endfield Industries. Damit kannst du 1 Rekrutierung in [Rekrutierung: Standard] durchführen.","desc":"Endfield Industries verfügt auf ganz Talos-II über Verbindungen und Ressourcen. Deshalb melden sich für beinahe jede Industriebranche umgehend viele Interessenten auf Stellenausschreibungen der Personalabteilung von Endfield."},"ap_supply_lt_n":{"name":"Verstandsverstärker für den Notfall","usage":"Verwenden, um 40 Verstand wiederherzustellen. Dieser Gegenstand hat ein Ablaufdatum.","desc":"Eine moderate Menge Verstandssirup, die in einem Notfallpaket enthalten ist. Der Entwickler scheint eine geheime Formel aus seltsamen Dokumenten erlangt zu haben, die die Menge an Zucker in dieser spezifischen Aufbereitung vervielfacht."},"item_bp_double_reward":{"name":"Verstandsverbrauch-Genehmigung","usage":"Verwenden, um die doppelte Menge an Verstand zu verbrauchen und so die doppelte Menge an Belohnungen von Verstand verbrauchenden Spielmodi zu beanspruchen. Pro 10 verbrauchtem Verstand muss 1 Genehmigung verbraucht werden.","desc":"Eine Genehmigung, die unverzüglich eine beträchtliche Menge an Verstand verbraucht. Übermäßiger Verbrauch von Verstand ist äußerst schädlich für den menschlichen Körper. Bevor du fortfährst, musst du dich einer kompletten medizinischen Untersuchung durch die Behandlungsabteilung unterziehen."},"item_char_break_stage_3_4":{"name":"Protoset","usage":"Ein Material, das Operatoren auf E3 oder E4 befördern kann.","desc":"Eine besondere Disk, die mit Techno-Protokoll und fortschrittlichen Datengravurprozessen gefertigt wurde. Wird oft von Operatoren beim Training eingesetzt und mit anderen Geräten kombiniert, um körperlicher Erschöpfung entgegenzuwirken."},"item_expcard_stage2_high":{"name":"Fortschrittlicher kognitiver Datenträger","usage":"Ein Material zum Aufleveln von Operatoren auf Lvl. 61–90, das sehr viele EP verleiht.","desc":"Ein Datenträger, der von Endfield Industries entwickelt wurde und mit verschiedenen Abspielgeräten kompatibel ist. Neue Operatoren können sich damit auf effektive Weise neue Kenntnisse aneignen. Dank der Unterstützung durch den Orden der Stille werden Daten auf diesem Datenträger automatisch komprimiert, was den effektiven Speicherplatz erhöht."},"item_weapon_break_high":{"name":"Schwere Gussform","usage":"Ein Material für die Waffenoptimierung.","desc":"Eine schwere Gussform aus seltenen Materialien. Nach der Aktivierung durch Techno-Protokoll kann diese Form das Material von Waffen insgesamt verstärken."},"item_char_skill_level_7_12":{"name":"Protoeder","usage":"Ein Material, das Operator-Fertigkeiten verbessern kann.","desc":"Ein besonderes Kristallpolyeder, das mit Techno-Protokoll und komplexen Kristallisationsprozessen gefertigt wurde. Wird oft mit anderen Geräten kombiniert, um die physiologische Aufnahme verbesserter Materialien zu optimieren."},"item_case_bp_selfselect_skillsp_1":{"name":"Erweiterter-Fortschritt-Auswahlkiste I","usage":"Nach dem Öffnen dieser Kiste erhältst du ein erweitertes Fortschrittsmaterial deiner Wahl.","desc":"Eine Kiste, die viele verschiedene Arten von hochwertigen, vielseitigen Materialien enthält. Spezies oder Kampferfahrung sagen nichts über die Kampfleistung eines Operators aus, sie hängt viel mehr davon ab, ob Inspiration vorhanden ist."}},"errMsg":{"code_2000":"Belohnungen konnten nicht gesendet werden. Bitte versuche es später erneut.","rewardClaimed":"Diese Belohnung wurde bereits abgeholt.","code_1002":"Das Event wird gerade geladen. Bitte warte kurz, bevor du die Eventanzeige erneut aufrufst.","code_1003":"Das Event ist beendet.","networkError":"Fehler des Dienstes"},"gamepad":{"hint":{"confirm":"Bestätigen","close":"Aus","closeCurrent":"Schließe diesen Bildschirm.","exit":"Seite verlassen"}}}'),a={lang:r.ELanguage["de-de"],text:t,fonts:{}}}}]);
